import { mutateData } from "../../../lib/utils/object.js";
import { getDockerfileContainers } from "../../docker/utils.js";
import springBoot4Dependencies from "../../spring-boot/resources/spring-boot-dependencies-4.js";
import springBoot3Dependencies from "../../spring-boot/resources/spring-boot-dependencies.js";
const ELASTICSEARCH_IMAGE = 'docker.elastic.co/elasticsearch/elasticsearch';
export function loadDockerDependenciesTask({ context }) {
    context.dockerContainers ??= {};
    const dockerfile = this.readTemplate(this.fetchFromInstalledJHipster('server/resources/Dockerfile'));
    mutateData(context.dockerContainers, this.prepareDependencies(getDockerfileContainers(dockerfile), 'docker'));
}
export function loadDockerElasticsearchVersion({ springBoot4, dockerContainers }) {
    const elasticsearchClientVersion = (springBoot4 ? springBoot4Dependencies : springBoot3Dependencies).properties['elasticsearch-client.version'];
    mutateData(dockerContainers, this.prepareDependencies({
        elasticsearchTag: elasticsearchClientVersion,
        elasticsearchImage: ELASTICSEARCH_IMAGE,
        elasticsearch: `${ELASTICSEARCH_IMAGE}:${elasticsearchClientVersion}`,
    }, 'docker'));
}
